import { MongoClient } from 'mongodb';
const client = new MongoClient(process.env.MONGO_URL || 'mongodb://mongodb:27017');
await client.connect();
const collection = client.db('codeleon').collection('notes');
await collection.insertOne({ body: 'hello mongo' });
console.log(`mongo docs: ${await collection.countDocuments()}`);
await client.close();
